it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
  // ##.   <- (0,0), (1,0)
  // #..   <- (0,1); dead cell (1,1) has exactly 3 live neighbors -> comes to life
  const nextGen = nextGeneration([
    [0, 0],
    [1, 0],
    [0, 1],
  ]);
  expect(nextGen).toContainEqual([1, 1]);
});
